public int max_computer_runtime(int n, int[] batteries) {
    Arrays.sort(batteries);
    int result = 0;
    for (int i = 0; i < batteries.length; i++) {
        result = Math.max(result, Math.min(n, batteries.length - i) * batteries[i]);
    }
    return result;
}
```


